module top_module(
    Q      ,
    obf_CLK    ,
    RESET_B
);output reg [1:0] Q;
    input  obf_CLK;
    input  RESET_B;

    always @(posedge obf_CLK or negedge RESET_B) begin
        if (!RESET_B) begin
            Q <= 2'b00;
        end else begin
            Q <= Q + 1;
        end
    end

endmodule
